"""The factor registry: 500+ deterministic factors, generated by systematic
parameterization rather than written by hand.

`quant/features.py` holds ~50 hand-picked features computed for the *latest* bar.
This module is the industrial version of the same idea: every factor is one entry
in `FACTOR_REGISTRY`, computable at *every* bar, and immediately rankable by the
Phase-7 IC machinery in `quant/ranking.py`.

Why a registry instead of a big function
----------------------------------------
Adding a factor must be one dict entry and nothing else. The moment a factor
lands in `FACTOR_REGISTRY` it appears in `factors <ASSET>` output, gets scored by
IC, and gets covered by the lookahead test — with no other change anywhere. A
god-function cannot give that guarantee.

The lookahead rule, enforced structurally
-----------------------------------------
A factor is a pure function `fn(bars, t) -> float | None` that may read only
indices `[0..t]`. Nothing in this file may index past `t`. `tests/test_factors.py`
pins this for *every* registry entry by recomputing each factor on a series
truncated at `t` and asserting the value is identical. If you add a factor that
peeks at the future, that test fails.

Coverage honesty
----------------
Every factor declares `min_bars`: the number of trailing candles it needs. Asked
for a value it cannot support, a factor returns `None` — never a plausible-looking
wrong number. A factor needing 252 bars on a 90-day series is `None` for every
bar, gets `coverage == 0.0`, and is reported as such.

Cost tiers
----------
Most factors are O(window) arithmetic. A handful (GARCH, HMM) fit a model per bar
and are hundreds of times slower. Those are tagged `cost="slow"` and excluded from
the default panel; pass `include_slow=True` (CLI: `--all-factors`) to opt in. This
keeps `factors BTC` a few seconds rather than a few minutes.
"""

from __future__ import annotations

import math
from collections.abc import Callable, Sequence
from dataclasses import dataclass

from alpha_engine.cache.models import Candle, PriceSeries
from alpha_engine.quant.features import (
    _mean,
    _pstd,
    _svar,
    ema_series,
    hurst_exponent,
    linreg,
    max_drawdown,
    shannon_entropy,
)

_ANNUAL = math.sqrt(252.0)


# ---------------------------------------------------------------------------
# Bars: the column-oriented view a factor reads
# ---------------------------------------------------------------------------


@dataclass(frozen=True, slots=True)
class Bars:
    """Column arrays for a whole series, built once per panel.

    Factors read slices of these lists rather than `Candle` objects. The reason
    is purely cost: building a pydantic model per bar per factor dominated
    everything else, and a panel is 500 factors x hundreds of bars. Slicing a
    plain list of floats is a C-level memcpy.

    `volume` is None when *any* bar lacks volume — a partially-populated volume
    column would silently make volume factors wrong rather than absent.
    """

    open: list[float]
    high: list[float]
    low: list[float]
    close: list[float]
    volume: list[float] | None

    def __len__(self) -> int:
        return len(self.close)

    @staticmethod
    def from_candles(candles: Sequence[Candle]) -> Bars:
        vols = [c.volume for c in candles]
        return Bars(
            open=[c.open for c in candles],
            high=[c.high for c in candles],
            low=[c.low for c in candles],
            close=[c.close for c in candles],
            volume=[float(v) for v in vols] if all(v is not None for v in vols) else None,
        )


FactorFn = Callable[[Bars, int], float | None]


@dataclass(frozen=True, slots=True)
class FactorSpec:
    """One factor. `fn(bars, t)` returns the value at bar `t` or None."""

    name: str
    family: str
    min_bars: int
    fn: FactorFn
    cost: str = "fast"  # "fast" | "slow" (slow = fits a model per bar)


# ---------------------------------------------------------------------------
# Slicing helpers. Every one of these refuses to read past `t`.
# ---------------------------------------------------------------------------


def _win(xs: list[float], t: int, n: int) -> list[float] | None:
    """The `n` values ending at index `t` inclusive, or None if unavailable."""
    start = t - n + 1
    if start < 0 or t >= len(xs):
        return None
    return xs[start : t + 1]


def _rets(closes: list[float]) -> list[float] | None:
    """Log returns of a close slice. None if any price is non-positive (a log
    of zero is undefined, not zero)."""
    out: list[float] = []
    for a, b in zip(closes, closes[1:]):
        if a <= 0 or b <= 0:
            return None
        out.append(math.log(b / a))
    return out


def _safe_div(a: float, b: float) -> float | None:
    return a / b if b != 0 else None


# ---------------------------------------------------------------------------
# Array-form volatility estimators.
#
# features.py has candle-form versions of these; the formulas are identical but
# the input shape is not, and rewriting features.py to be column-oriented would
# mean rewriting working, tested code for no user-visible gain.
# ---------------------------------------------------------------------------


def _parkinson(high: list[float], low: list[float]) -> float | None:
    terms = []
    for h, lo in zip(high, low):
        if lo <= 0 or h < lo:
            return None
        terms.append(math.log(h / lo) ** 2)
    if not terms or sum(terms) <= 0:
        return None
    return math.sqrt(_mean(terms) / (4.0 * math.log(2.0))) * _ANNUAL


def _garman_klass(o: list[float], h: list[float], lo: list[float], c: list[float]) -> float | None:
    terms = []
    for oo, hh, ll, cc in zip(o, h, lo, c):
        if ll <= 0 or oo <= 0 or hh < ll:
            return None
        terms.append(
            0.5 * math.log(hh / ll) ** 2 - (2.0 * math.log(2.0) - 1.0) * math.log(cc / oo) ** 2
        )
    if not terms:
        return None
    m = _mean(terms)
    return math.sqrt(m) * _ANNUAL if m > 0 else None


def _yang_zhang(o: list[float], h: list[float], lo: list[float], c: list[float]) -> float | None:
    n = len(c) - 1
    if n < 2:
        return None
    overnight, openclose, rs = [], [], []
    for i in range(1, len(c)):
        if min(c[i - 1], o[i], c[i], h[i], lo[i]) <= 0:
            return None
        overnight.append(math.log(o[i] / c[i - 1]))
        openclose.append(math.log(c[i] / o[i]))
        rs.append(
            math.log(h[i] / c[i]) * math.log(h[i] / o[i])
            + math.log(lo[i] / c[i]) * math.log(lo[i] / o[i])
        )
    k = 0.34 / (1.34 + (n + 1) / (n - 1))
    var = _svar(overnight) + k * _svar(openclose) + (1.0 - k) * _mean(rs)
    return math.sqrt(var) * _ANNUAL if var >= 0 else None


def _true_ranges(h: list[float], lo: list[float], c: list[float]) -> list[float]:
    """True range for bars 1..n-1 (bar 0 has no previous close)."""
    return [
        max(h[i] - lo[i], abs(h[i] - c[i - 1]), abs(lo[i] - c[i - 1])) for i in range(1, len(c))
    ]


def _corr(xs: list[float], ys: list[float]) -> float | None:
    if len(xs) != len(ys) or len(xs) < 3:
        return None
    sx, sy = _pstd(xs), _pstd(ys)
    if sx == 0 or sy == 0:
        return None
    mx, my = _mean(xs), _mean(ys)
    cov = _mean([(x - mx) * (y - my) for x, y in zip(xs, ys)])
    return max(-1.0, min(1.0, cov / (sx * sy)))


def _wma(xs: list[float]) -> float:
    """Linearly weighted moving average: the most recent bar weighs the most."""
    n = len(xs)
    denom = n * (n + 1) / 2.0
    return sum((i + 1) * x for i, x in enumerate(xs)) / denom


def _pct_rank(x: float, xs: list[float]) -> float:
    return sum(1 for v in xs if v <= x) / len(xs)


# ---------------------------------------------------------------------------
# The N grid. One place to widen or narrow the whole library.
# ---------------------------------------------------------------------------

N_GRID: tuple[int, ...] = (1, 2, 3, 5, 10, 15, 20, 30, 40, 60, 90, 120, 180, 252)
VOL_GRID: tuple[int, ...] = (5, 10, 15, 20, 30, 40, 60, 90, 120, 180, 252)
MA_GRID: tuple[int, ...] = (5, 10, 20, 50, 100, 200)
MID_GRID: tuple[int, ...] = (5, 10, 20, 40, 60, 120)
LONG_GRID: tuple[int, ...] = (60, 120, 252)

FACTOR_REGISTRY: dict[str, FactorSpec] = {}


def register(spec: FactorSpec) -> None:
    """Add a factor. Duplicate names are a bug, not a silent overwrite — a
    shadowed factor would vanish from the rankings with no error anywhere."""
    if spec.name in FACTOR_REGISTRY:
        raise ValueError(f"duplicate factor name: {spec.name}")
    FACTOR_REGISTRY[spec.name] = spec


def _add(name: str, family: str, min_bars: int, fn: FactorFn, cost: str = "fast") -> None:
    register(FactorSpec(name=name, family=family, min_bars=min_bars, fn=fn, cost=cost))


# ---------------------------------------------------------------------------
# Family 1 — momentum / reversal
# ---------------------------------------------------------------------------


def _mom(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None or w[0] <= 0:
            return None
        return w[-1] / w[0] - 1.0

    return fn


def _mom_volnorm(n: int) -> FactorFn:
    """Momentum divided by the volatility of the same window. Puts a 2% move in
    a calm tape and a 2% move in a violent one on the same scale."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None or w[0] <= 0:
            return None
        r = _rets(w)
        if r is None or len(r) < 2:
            return None
        sd = _pstd(r)
        return _safe_div(w[-1] / w[0] - 1.0, sd)

    return fn


def _mom_skip1(n: int) -> FactorFn:
    """Return from t-n to t-1, skipping the most recent bar. The classic
    academic momentum construction: the newest bar is dominated by short-term
    reversal, so leaving it out isolates the slower trend."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 2)
        if w is None or w[0] <= 0:
            return None
        return w[-2] / w[0] - 1.0

    return fn


def _mom_accel(n: int) -> FactorFn:
    """Recent momentum minus the momentum of the window twice as long. Positive
    = the move is speeding up rather than just continuing."""

    def fn(b: Bars, t: int) -> float | None:
        a, c = _mom(n)(b, t), _mom(2 * n)(b, t)
        if a is None or c is None:
            return None
        return a - c

    return fn


def _mom_rank(n: int, hist: int) -> FactorFn:
    """Percentile rank of the current n-bar return within its own last `hist`
    bars of history. Scale-free, so a 5% move means something different in a
    quiet asset than a wild one — which raw momentum cannot express."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, hist + n + 1)
        if w is None:
            return None
        rolls = [w[i] / w[i - n] - 1.0 for i in range(n, len(w)) if w[i - n] > 0]
        if len(rolls) < 10:
            return None
        return _pct_rank(rolls[-1], rolls)

    return fn


for _n in N_GRID:
    _add(f"mom_{_n}", "momentum", _n + 1, _mom(_n))
    # vol-normalizing needs at least two returns to have a deviation at all,
    # so the 1-bar variant is skipped rather than registered as a permanent None
    if _n >= 2:
        _add(f"mom_volnorm_{_n}", "momentum", _n + 1, _mom_volnorm(_n))
for _n in N_GRID[2:]:  # skip-a-bar is meaningless below ~3 bars
    _add(f"mom_skip1_{_n}", "momentum", _n + 2, _mom_skip1(_n))
for _n in (5, 10, 20, 60, 120):
    _add(f"mom_accel_{_n}", "momentum", 2 * _n + 1, _mom_accel(_n))
    _add(f"mom_rank_{_n}", "momentum", 252 + _n + 1, _mom_rank(_n, 252))


# ---------------------------------------------------------------------------
# Family 2 — moving-average structure
# ---------------------------------------------------------------------------


def _ma_value(kind: str, w: list[float]) -> float | None:
    if kind == "sma":
        return _mean(w)
    if kind == "wma":
        return _wma(w)
    e = ema_series(w, len(w))
    return e[-1] if e else None


def _dist_ma(kind: str, n: int) -> FactorFn:
    """Percent distance of price from its moving average — the stretch."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None:
            return None
        ma = _ma_value(kind, w)
        if ma is None or ma <= 0:
            return None
        return w[-1] / ma - 1.0

    return fn


def _ma_slope(kind: str, n: int) -> FactorFn:
    """Percent change of the moving average over the last ~n/4 bars. Direction
    of the average rather than distance from it."""
    lag = max(1, n // 4)

    def fn(b: Bars, t: int) -> float | None:
        now = _win(b.close, t, n)
        prev = _win(b.close, t - lag, n)
        if now is None or prev is None:
            return None
        a, c = _ma_value(kind, prev), _ma_value(kind, now)
        if a is None or c is None or a <= 0:
            return None
        return c / a - 1.0

    return fn


def _ma_cross(kind: str, fast: int, slow: int) -> FactorFn:
    """Fast MA minus slow MA, normalized by the slow MA. Positive = the classic
    golden-cross posture."""

    def fn(b: Bars, t: int) -> float | None:
        wf, ws = _win(b.close, t, fast), _win(b.close, t, slow)
        if wf is None or ws is None:
            return None
        a, c = _ma_value(kind, wf), _ma_value(kind, ws)
        if a is None or c is None or c <= 0:
            return None
        return a / c - 1.0

    return fn


_MA_KINDS = ("sma", "ema", "wma")
_MA_PAIRS = [(f, s) for f in MA_GRID for s in MA_GRID if f < s]

for _kind in _MA_KINDS:
    for _n in N_GRID[3:]:  # a 1-2 bar "average" is just the price
        _add(f"dist_{_kind}_{_n}", "ma_structure", _n, _dist_ma(_kind, _n))
        _add(f"slope_{_kind}_{_n}", "ma_structure", _n + max(1, _n // 4), _ma_slope(_kind, _n))
    for _f, _s in _MA_PAIRS:
        _add(f"cross_{_kind}_{_f}_{_s}", "ma_structure", _s, _ma_cross(_kind, _f, _s))


# ---------------------------------------------------------------------------
# Family 3 — volatility
# ---------------------------------------------------------------------------


def _realized_vol(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 2:
            return None
        return _pstd(r) * _ANNUAL

    return fn


def _semivol(n: int, downside: bool) -> FactorFn:
    """Volatility of only the down (or only the up) returns. A tape that falls
    violently and rises gently has the same realized vol as the reverse; these
    two do not."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None:
            return None
        side = [x for x in r if (x < 0 if downside else x > 0)]
        if len(side) < 2:
            return None
        return _pstd(side) * _ANNUAL

    return fn


def _range_vol(kind: str, n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        need = n + 1 if kind == "yz" else n
        if t - need + 1 < 0:
            return None
        o = _win(b.open, t, need)
        h = _win(b.high, t, need)
        lo = _win(b.low, t, need)
        c = _win(b.close, t, need)
        if o is None or h is None or lo is None or c is None:
            return None
        if kind == "parkinson":
            return _parkinson(h, lo)
        if kind == "gk":
            return _garman_klass(o, h, lo, c)
        return _yang_zhang(o, h, lo, c)

    return fn


def _atr_pct(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        h, lo, c = _win(b.high, t, n + 1), _win(b.low, t, n + 1), _win(b.close, t, n + 1)
        if h is None or lo is None or c is None or c[-1] <= 0:
            return None
        trs = _true_ranges(h, lo, c)
        return _mean(trs) / c[-1] if trs else None

    return fn


def _vol_ratio(short: int, long: int) -> FactorFn:
    """Short-horizon vol over long-horizon vol. Above 1 = the tape just woke up."""

    def fn(b: Bars, t: int) -> float | None:
        a = _realized_vol(short)(b, t)
        c = _realized_vol(long)(b, t)
        if a is None or c is None:
            return None
        return _safe_div(a, c)

    return fn


def _vol_of_vol(n: int) -> FactorFn:
    """Dispersion of rolling 10-bar vol. High = the volatility regime itself is
    unstable, which is different from volatility being high."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 11)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 20:
            return None
        rolling = [_pstd(r[i - 10 : i]) * _ANNUAL for i in range(10, len(r) + 1)]
        return _pstd(rolling)

    return fn


def _vol_percentile(n: int) -> FactorFn:
    """Where current 20-bar vol sits inside its own last-n history. Scale-free,
    so it is comparable across assets in a way raw vol is not."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 21)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 21:
            return None
        hist = [_pstd(r[i - 20 : i]) * _ANNUAL for i in range(20, len(r) + 1)]
        return _pct_rank(hist[-1], hist)

    return fn


def _ewma_vol(n: int, lam: float) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 10:
            return None
        var = _mean([x * x for x in r[:10]])
        for x in r[10:]:
            var = lam * var + (1.0 - lam) * x * x
        return math.sqrt(var) * _ANNUAL

    return fn


for _n in VOL_GRID:
    _add(f"rvol_{_n}", "volatility", _n + 1, _realized_vol(_n))
    _add(f"parkinson_{_n}", "volatility", _n, _range_vol("parkinson", _n))
    _add(f"garman_klass_{_n}", "volatility", _n, _range_vol("gk", _n))
    _add(f"yang_zhang_{_n}", "volatility", _n + 1, _range_vol("yz", _n))
    _add(f"atr_pct_{_n}", "volatility", _n + 1, _atr_pct(_n))
for _n in (20, 60, 120):
    _add(f"semivol_down_{_n}", "volatility", _n + 1, _semivol(_n, downside=True))
    _add(f"semivol_up_{_n}", "volatility", _n + 1, _semivol(_n, downside=False))
for _s, _l in ((5, 20), (10, 60), (20, 120), (20, 252), (60, 252)):
    _add(f"vol_ratio_{_s}_{_l}", "volatility", _l + 1, _vol_ratio(_s, _l))
for _n in (20, 60):
    _add(f"vol_of_vol_{_n}", "volatility", _n + 11, _vol_of_vol(_n))
for _n in LONG_GRID:
    _add(f"vol_percentile_{_n}", "volatility", _n + 21, _vol_percentile(_n))
for _lam in (0.94, 0.97):
    _add(
        f"ewma_vol_{str(_lam).replace('.', '')}",
        "volatility",
        61,
        _ewma_vol(60, _lam),
    )


# ---------------------------------------------------------------------------
# Family 4 — volume / participation
# ---------------------------------------------------------------------------


def _needs_volume(fn: Callable[[Bars, int, list[float]], float | None], n: int) -> FactorFn:
    """Wrap a volume factor so a series without volume returns None everywhere
    rather than raising. Forex and some macro sources have no volume at all."""

    def wrapped(b: Bars, t: int) -> float | None:
        if b.volume is None:
            return None
        v = _win(b.volume, t, n)
        if v is None:
            return None
        return fn(b, t, v)

    return wrapped


def _volume_z(n: int) -> FactorFn:
    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        sd = _pstd(v)
        return _safe_div(v[-1] - _mean(v), sd)

    return _needs_volume(inner, n)


def _rel_volume(n: int) -> FactorFn:
    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        return _safe_div(v[-1], _mean(v))

    return _needs_volume(inner, n)


def _volume_percentile(n: int) -> FactorFn:
    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        return _pct_rank(v[-1], v)

    return _needs_volume(inner, n)


def _obv_slope(n: int) -> FactorFn:
    """Slope of on-balance volume, in units of average daily volume per bar, so
    the number is comparable across assets."""

    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        c = _win(b.close, t, n)
        if c is None:
            return None
        obv, acc = [], 0.0
        for i in range(1, len(c)):
            if c[i] > c[i - 1]:
                acc += v[i]
            elif c[i] < c[i - 1]:
                acc -= v[i]
            obv.append(acc)
        fit = linreg(obv)
        vm = _mean(v)
        if fit is None or vm <= 0:
            return None
        return fit[0] / vm

    return _needs_volume(inner, n)


def _price_volume_corr(n: int) -> FactorFn:
    """Correlation of returns with volume. Positive = moves come with
    participation; negative = the tape drifts on thin volume."""

    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        c = _win(b.close, t, n + 1)
        if c is None:
            return None
        r = _rets(c)
        if r is None or len(r) != len(v):
            return None
        return _corr(r, v)

    return _needs_volume(inner, n)


def _amihud(n: int) -> FactorFn:
    """Amihud illiquidity: average |return| per unit of dollar volume. High =
    small trades move the price a lot = illiquid."""

    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        c = _win(b.close, t, n + 1)
        if c is None:
            return None
        r = _rets(c)
        if r is None or len(r) != len(v):
            return None
        terms = [abs(x) / (vv * cc) for x, vv, cc in zip(r, v, c[1:]) if vv > 0 and cc > 0]
        return _mean(terms) * 1e6 if terms else None

    return _needs_volume(inner, n)


def _dollar_volume_trend(n: int) -> FactorFn:
    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        c = _win(b.close, t, n)
        if c is None:
            return None
        dv = [vv * cc for vv, cc in zip(v, c)]
        fit = linreg(dv)
        m = _mean(dv)
        if fit is None or m <= 0:
            return None
        return fit[0] / m

    return _needs_volume(inner, n)


def _updown_volume_ratio(n: int) -> FactorFn:
    """Volume on up bars over volume on down bars. Above 1 = buyers are the
    ones showing up."""

    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        c = _win(b.close, t, n)
        if c is None:
            return None
        up = sum(v[i] for i in range(1, len(c)) if c[i] > c[i - 1])
        dn = sum(v[i] for i in range(1, len(c)) if c[i] < c[i - 1])
        return _safe_div(up, dn)

    return _needs_volume(inner, n)


def _dist_vwap(n: int) -> FactorFn:
    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        h, lo, c = _win(b.high, t, n), _win(b.low, t, n), _win(b.close, t, n)
        if h is None or lo is None or c is None:
            return None
        num = sum((hh + ll + cc) / 3.0 * vv for hh, ll, cc, vv in zip(h, lo, c, v))
        den = sum(v)
        if den <= 0 or num <= 0:
            return None
        return c[-1] / (num / den) - 1.0

    return _needs_volume(inner, n)


def _volume_trend(n: int) -> FactorFn:
    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        fit = linreg(v)
        m = _mean(v)
        if fit is None or m <= 0:
            return None
        return fit[0] / m

    return _needs_volume(inner, n)


