# ---------------------------------------------------------------------------
# Family 5 — distribution / statistical structure
# ---------------------------------------------------------------------------


def _skew(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 3:
            return None
        sd = _pstd(r)
        if sd <= 0:
            return None
        m = _mean(r)
        return _mean([((x - m) / sd) ** 3 for x in r])

    return fn


def _kurtosis(n: int) -> FactorFn:
    """Excess kurtosis: how fat the tails are relative to a normal (which is 0)."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 4:
            return None
        sd = _pstd(r)
        if sd <= 0:
            return None
        m = _mean(r)
        return _mean([((x - m) / sd) ** 4 for x in r]) - 3.0

    return fn


def _autocorr(lag: int, n: int) -> FactorFn:
    """Correlation of returns with themselves `lag` bars ago. Positive =
    trending at that lag; negative = mean-reverting."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + lag + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < n + lag:
            return None
        return _corr(r[:-lag], r[lag:])

    return fn


def _variance_ratio(q: int, n: int) -> FactorFn:
    """Lo-MacKinlay variance ratio: variance of q-bar returns over q x variance
    of 1-bar returns. 1.0 = random walk, >1 = trending, <1 = mean-reverting."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < q * 4:
            return None
        v1 = _svar(r)
        agg = [sum(r[i : i + q]) for i in range(0, len(r) - q + 1)]
        if v1 <= 0 or len(agg) < 2:
            return None
        return _svar(agg) / (q * v1)

    return fn


def _zscore(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None:
            return None
        return _safe_div(w[-1] - _mean(w), _pstd(w))

    return fn


def _entropy(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        return shannon_entropy(r) if r else None

    return fn


def _hurst(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        return hurst_exponent(w, max_points=n) if w else None

    return fn


def _max_dd(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        return max_drawdown(w) if w else None

    return fn


def _positive_bar_share(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if not r:
            return None
        return sum(1 for x in r if x > 0) / len(r)

    return fn


def _tail_ratio(n: int) -> FactorFn:
    """95th percentile return over |5th percentile|. Above 1 = the good tail is
    bigger than the bad one."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 20:
            return None
        s = sorted(r)
        hi = s[int(0.95 * (len(s) - 1))]
        lo = s[int(0.05 * (len(s) - 1))]
        return _safe_div(hi, abs(lo))

    return fn


