# ---------------------------------------------------------------------------
# Family 6 — trend quality
# ---------------------------------------------------------------------------


def _lr(field: str, n: int, part: str) -> FactorFn:
    """Least-squares fit over the window. `part` picks slope (normalized to
    percent-per-bar), r2 (how straight the move was), or the slope's t-stat."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None:
            return None
        ys = w
        if field == "log":
            if any(x <= 0 for x in w):
                return None
            ys = [math.log(x) for x in w]
        fit = linreg(ys)
        if fit is None:
            return None
        slope, intercept, r2 = fit
        if part == "r2":
            return r2
        if part == "slope":
            if field == "log":
                return slope
            m = _mean(ys)
            return slope / m if m > 0 else None
        # t-stat of the slope: slope / standard error of slope
        nn = len(ys)
        if nn < 4:
            return None
        resid = [y - (intercept + slope * i) for i, y in enumerate(ys)]
        sse = sum(e * e for e in resid)
        mx = _mean([float(i) for i in range(nn)])
        sxx = sum((i - mx) ** 2 for i in range(nn))
        if sse <= 0 or sxx <= 0:
            return None
        se = math.sqrt(sse / (nn - 2) / sxx)
        return _safe_div(slope, se)

    return fn


def _slope_stability(n: int) -> FactorFn:
    """Dispersion of rolling 20-bar slopes. Low = the trend has been steady;
    high = the trend keeps changing its mind."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None or len(w) < 40:
            return None
        slopes = []
        for i in range(20, len(w) + 1):
            fit = linreg(w[i - 20 : i])
            m = _mean(w[i - 20 : i])
            if fit is not None and m > 0:
                slopes.append(fit[0] / m)
        return _pstd(slopes) if len(slopes) >= 3 else None

    return fn


def _efficiency_ratio(n: int) -> FactorFn:
    """Kaufman efficiency: net move over total path travelled. 1.0 = a straight
    line, near 0 = the same distance covered by thrashing."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        net = abs(w[-1] - w[0])
        path = sum(abs(y - x) for x, y in zip(w, w[1:]))
        return _safe_div(net, path)

    return fn


def _adx(n: int) -> FactorFn:
    """Average Directional Index: trend strength regardless of direction."""

    def fn(b: Bars, t: int) -> float | None:
        need = 2 * n + 1
        h, lo, c = _win(b.high, t, need), _win(b.low, t, need), _win(b.close, t, need)
        if h is None or lo is None or c is None:
            return None
        trs, plus_dm, minus_dm = [], [], []
        for i in range(1, len(c)):
            up, down = h[i] - h[i - 1], lo[i - 1] - lo[i]
            plus_dm.append(up if up > down and up > 0 else 0.0)
            minus_dm.append(down if down > up and down > 0 else 0.0)
            trs.append(max(h[i] - lo[i], abs(h[i] - c[i - 1]), abs(lo[i] - c[i - 1])))
        dxs = []
        for i in range(n, len(trs) + 1):
            tr = sum(trs[i - n : i])
            if tr <= 0:
                continue
            pdi = 100.0 * sum(plus_dm[i - n : i]) / tr
            mdi = 100.0 * sum(minus_dm[i - n : i]) / tr
            if pdi + mdi > 0:
                dxs.append(100.0 * abs(pdi - mdi) / (pdi + mdi))
        return _mean(dxs) if len(dxs) >= 2 else None

    return fn


def _trend_persistence(n: int) -> FactorFn:
    """Share of bars whose direction agreed with the window's net direction."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if not r:
            return None
        net = sum(r)
        if net == 0:
            return 0.5
        return sum(1 for x in r if (x > 0) == (net > 0)) / len(r)

    return fn


def _macd_hist(fast: int, slow: int, signal: int) -> FactorFn:
    """MACD histogram normalized by price, so it is comparable across assets."""

    def fn(b: Bars, t: int) -> float | None:
        need = slow + signal + 10
        w = _win(b.close, t, need)
        if w is None:
            return None
        ef, es = ema_series(w, fast), ema_series(w, slow)
        if not ef or not es:
            return None
        macd = [a - c for a, c in zip(ef[-len(es) :], es)]
        sig = ema_series(macd, signal)
        if not sig or w[-1] <= 0:
            return None
        return (macd[-1] - sig[-1]) / w[-1]

    return fn


