# ---------------------------------------------------------------------------
# Family 7 — range / structure
# ---------------------------------------------------------------------------


def _dist_high(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        h, c = _win(b.high, t, n), _win(b.close, t, n)
        if h is None or c is None:
            return None
        hi = max(h)
        return c[-1] / hi - 1.0 if hi > 0 else None

    return fn


def _dist_low(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        lo, c = _win(b.low, t, n), _win(b.close, t, n)
        if lo is None or c is None:
            return None
        low = min(lo)
        return c[-1] / low - 1.0 if low > 0 else None

    return fn


def _range_position(n: int) -> FactorFn:
    """Where price sits inside the n-bar range: 0 = at the low, 1 = at the high."""

    def fn(b: Bars, t: int) -> float | None:
        h, lo, c = _win(b.high, t, n), _win(b.low, t, n), _win(b.close, t, n)
        if h is None or lo is None or c is None:
            return None
        hi, low = max(h), min(lo)
        return _safe_div(c[-1] - low, hi - low)

    return fn


def _donchian_width(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        h, lo, c = _win(b.high, t, n), _win(b.low, t, n), _win(b.close, t, n)
        if h is None or lo is None or c is None or c[-1] <= 0:
            return None
        return (max(h) - min(lo)) / c[-1]

    return fn


def _consecutive_bars(n: int) -> FactorFn:
    """Signed run length: +3 = three up bars in a row, -2 = two down bars."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if not r:
            return None
        sign = 1 if r[-1] > 0 else -1 if r[-1] < 0 else 0
        if sign == 0:
            return 0.0
        run = 0
        for x in reversed(r):
            if (x > 0) == (sign > 0) and x != 0:
                run += 1
            else:
                break
        return float(run * sign)

    return fn


def _bb_pct_b(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None:
            return None
        m, s = _mean(w), _pstd(w)
        if s <= 0:
            return 0.5
        return (w[-1] - (m - 2 * s)) / (4 * s)

    return fn


def _bb_width(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None:
            return None
        m = _mean(w)
        return 4 * _pstd(w) / m if m > 0 else None

    return fn


def _keltner_width(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        h, lo, c = _win(b.high, t, n + 1), _win(b.low, t, n + 1), _win(b.close, t, n + 1)
        if h is None or lo is None or c is None:
            return None
        trs = _true_ranges(h, lo, c)
        e = ema_series(c, len(c))
        if not trs or not e or e[-1] <= 0:
            return None
        return 4.0 * _mean(trs) / e[-1]

    return fn


def _compression(short: int, long: int) -> FactorFn:
    """Positive = recent ranges are tighter than the longer window (a coil)."""

    def fn(b: Bars, t: int) -> float | None:
        h, lo, c = _win(b.high, t, long + 1), _win(b.low, t, long + 1), _win(b.close, t, long + 1)
        if h is None or lo is None or c is None:
            return None
        trs = _true_ranges(h, lo, c)
        if len(trs) < long:
            return None
        recent, baseline = _mean(trs[-short:]), _mean(trs[-long:])
        return 1.0 - recent / baseline if baseline > 0 else None

    return fn


def _range_percentile(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        h, lo, c = _win(b.high, t, n), _win(b.low, t, n), _win(b.close, t, n)
        if h is None or lo is None or c is None:
            return None
        rngs = [(hh - ll) / cc for hh, ll, cc in zip(h, lo, c) if cc > 0]
        return _pct_rank(rngs[-1], rngs) if rngs else None

    return fn


def _gap_pct(b: Bars, t: int) -> float | None:
    if t < 1 or b.close[t - 1] <= 0:
        return None
    return b.open[t] / b.close[t - 1] - 1.0


def _mean_gap(n: int) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        o, c = _win(b.open, t, n), _win(b.close, t, n)
        if o is None or c is None or t - n < 0:
            return None
        prev_c = b.close[t - n : t]
        gaps = [oo / pc - 1.0 for oo, pc in zip(o, prev_c) if pc > 0]
        return _mean(gaps) if gaps else None

    return fn


def _candle_part(part: str) -> FactorFn:
    """Shape of the most recent bar: body share, wick shares, and close
    location value (where it closed inside its own range)."""

    def fn(b: Bars, t: int) -> float | None:
        o, h, lo, c = b.open[t], b.high[t], b.low[t], b.close[t]
        full = h - lo
        if full <= 0:
            return None
        if part == "body":
            return abs(c - o) / full
        if part == "upper_wick":
            return (h - max(o, c)) / full
        if part == "lower_wick":
            return (min(o, c) - lo) / full
        return ((c - lo) - (h - c)) / full

    return fn


