# ---------------------------------------------------------------------------
# Family 8 — classic oscillators
#
# These are the textbook indicators (RSI, stochastics, CCI, Williams %R, money
# flow). The registry had none of them: `analyzers/rsi.py` computes RSI for the
# signal path, but it was never available as a *rankable* factor, so nobody
# could measure whether RSI predicts anything on a given asset. Now it is.
# ---------------------------------------------------------------------------


def _rsi(n: int) -> FactorFn:
    """Wilder's RSI: average gain over average loss, mapped to 0-100."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        gains = [max(0.0, y - x) for x, y in zip(w, w[1:])]
        losses = [max(0.0, x - y) for x, y in zip(w, w[1:])]
        ag, al = _mean(gains), _mean(losses)
        if ag + al == 0:
            return 50.0
        return 100.0 * ag / (ag + al)

    return fn


def _stochastic(n: int, smooth: int) -> FactorFn:
    """%K (smooth=1) or %D (smooth>1): where the close sits in the n-bar
    high-low range, optionally averaged over the last `smooth` values."""

    def fn(b: Bars, t: int) -> float | None:
        vals = []
        for i in range(t - smooth + 1, t + 1):
            h, lo, c = _win(b.high, i, n), _win(b.low, i, n), _win(b.close, i, n)
            if h is None or lo is None or c is None:
                return None
            hi, low = max(h), min(lo)
            k = _safe_div(c[-1] - low, hi - low)
            if k is None:
                return None
            vals.append(100.0 * k)
        return _mean(vals) if vals else None

    return fn


def _cci(n: int) -> FactorFn:
    """Commodity Channel Index: typical price versus its average, scaled by
    mean absolute deviation."""

    def fn(b: Bars, t: int) -> float | None:
        h, lo, c = _win(b.high, t, n), _win(b.low, t, n), _win(b.close, t, n)
        if h is None or lo is None or c is None:
            return None
        tp = [(hh + ll + cc) / 3.0 for hh, ll, cc in zip(h, lo, c)]
        m = _mean(tp)
        mad = _mean([abs(x - m) for x in tp])
        return _safe_div(tp[-1] - m, 0.015 * mad)

    return fn


def _williams_r(n: int) -> FactorFn:
    """Williams %R: the stochastic read inverted, on a -100..0 scale."""

    def fn(b: Bars, t: int) -> float | None:
        h, lo, c = _win(b.high, t, n), _win(b.low, t, n), _win(b.close, t, n)
        if h is None or lo is None or c is None:
            return None
        hi, low = max(h), min(lo)
        r = _safe_div(hi - c[-1], hi - low)
        return -100.0 * r if r is not None else None

    return fn


def _money_flow_index(n: int) -> FactorFn:
    """RSI computed on money flow (typical price x volume) rather than price."""

    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        h, lo, c = _win(b.high, t, n), _win(b.low, t, n), _win(b.close, t, n)
        if h is None or lo is None or c is None:
            return None
        tp = [(hh + ll + cc) / 3.0 for hh, ll, cc in zip(h, lo, c)]
        pos = sum(tp[i] * v[i] for i in range(1, len(tp)) if tp[i] > tp[i - 1])
        neg = sum(tp[i] * v[i] for i in range(1, len(tp)) if tp[i] < tp[i - 1])
        if pos + neg == 0:
            return 50.0
        return 100.0 * pos / (pos + neg)

    return _needs_volume(inner, n)


def _chaikin_money_flow(n: int) -> FactorFn:
    """Volume weighted by where each bar closed inside its own range. Positive
    = volume is arriving on closes near the highs."""

    def inner(b: Bars, t: int, v: list[float]) -> float | None:
        h, lo, c = _win(b.high, t, n), _win(b.low, t, n), _win(b.close, t, n)
        if h is None or lo is None or c is None:
            return None
        num = 0.0
        for hh, ll, cc, vv in zip(h, lo, c, v):
            rng = hh - ll
            if rng > 0:
                num += ((cc - ll) - (hh - cc)) / rng * vv
        return _safe_div(num, sum(v))

    return _needs_volume(inner, n)


for _n in (7, 14, 21, 28):
    _add(f"rsi_{_n}", "oscillator", _n + 1, _rsi(_n))
for _n in (14, 28):
    _add(f"stoch_k_{_n}", "oscillator", _n, _stochastic(_n, 1))
    _add(f"stoch_d_{_n}", "oscillator", _n + 2, _stochastic(_n, 3))
    _add(f"williams_r_{_n}", "oscillator", _n, _williams_r(_n))
    _add(f"money_flow_index_{_n}", "oscillator", _n, _money_flow_index(_n))
for _n in (20, 40):
    _add(f"cci_{_n}", "oscillator", _n, _cci(_n))
for _n in (20, 60):
    _add(f"chaikin_money_flow_{_n}", "oscillator", _n, _chaikin_money_flow(_n))


# ---------------------------------------------------------------------------
# Family 9 — risk-adjusted return
#
# Return per unit of pain. These are the shapes a track record is judged by,
# and they behave differently from raw momentum: an asset can have strong
# momentum and a terrible Sharpe if it got there through violent swings.
# ---------------------------------------------------------------------------


def _sharpe(n: int) -> FactorFn:
    """Mean return over its standard deviation, annualized. No risk-free rate
    subtracted: this is a cross-sectional ranking factor, not a fund report,
    and a constant offset does not change a rank."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 3:
            return None
        return _safe_div(_mean(r) * 252.0, _pstd(r) * _ANNUAL)

    return fn


def _sortino(n: int) -> FactorFn:
    """Sharpe but penalizing only downside deviation. Upside volatility is not
    a problem anyone actually has."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None or len(r) < 3:
            return None
        down = [x for x in r if x < 0]
        if len(down) < 2:
            return None
        return _safe_div(_mean(r) * 252.0, _pstd(down) * _ANNUAL)

    return fn


def _calmar(n: int) -> FactorFn:
    """Return over worst drawdown across the window."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None or w[0] <= 0:
            return None
        dd = max_drawdown(w)
        if dd is None or dd >= 0:
            return None
        return (w[-1] / w[0] - 1.0) / abs(dd)

    return fn


def _ulcer_index(n: int) -> FactorFn:
    """Root-mean-square drawdown: unlike max drawdown, it cares how *long* the
    asset stayed underwater, not just how deep it went."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None:
            return None
        peak = w[0]
        sq = []
        for x in w:
            peak = max(peak, x)
            if peak > 0:
                sq.append((100.0 * (x / peak - 1.0)) ** 2)
        return math.sqrt(_mean(sq)) if sq else None

    return fn


def _drawdown_now(n: int) -> FactorFn:
    """Current distance below the running peak — where the asset is *now*,
    as opposed to the worst it ever got."""

    def fn(b: Bars, t: int) -> float | None:
        w = _win(b.close, t, n)
        if w is None:
            return None
        peak = max(w)
        return w[-1] / peak - 1.0 if peak > 0 else None

    return fn


for _n in (20, 60, 120, 252):
    _add(f"sharpe_{_n}", "risk_adjusted", _n + 1, _sharpe(_n))
    _add(f"ulcer_index_{_n}", "risk_adjusted", _n, _ulcer_index(_n))
    _add(f"drawdown_now_{_n}", "risk_adjusted", _n, _drawdown_now(_n))
for _n in (60, 120, 252):
    _add(f"sortino_{_n}", "risk_adjusted", _n + 1, _sortino(_n))
for _n in (120, 252):
    _add(f"calmar_{_n}", "risk_adjusted", _n, _calmar(_n))


# ---------------------------------------------------------------------------
# Family 10 — derived-model factors
#
# Kalman is a single O(n) pass and stays "fast". GARCH and HMM each run an
# iterative fit; at one fit per bar per factor they are ~100x the cost of
# everything else in this file combined, so they are tagged "slow" and left out
# of the default panel. This is a real ceiling, not a guess: measure before
# assuming it changed.
# ---------------------------------------------------------------------------


def _kalman(n: int, part: str) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        from alpha_engine.quant.models import kalman_fair_value

        w = _win(b.close, t, n)
        if w is None:
            return None
        k = kalman_fair_value(w)
        if k is None:
            return None
        return k.distance if part == "distance" else k.slope

    return fn


def _garch(n: int, part: str) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        from alpha_engine.quant.models import fit_garch

        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None:
            return None
        g = fit_garch(r)
        if g is None:
            return None
        if part == "forecast":
            return g.forecast_vol_annual
        rv = _pstd(r) * _ANNUAL
        return _safe_div(g.forecast_vol_annual, rv)

    return fn


def _hmm(n: int, part: str) -> FactorFn:
    def fn(b: Bars, t: int) -> float | None:
        from alpha_engine.quant.models import fit_hmm

        w = _win(b.close, t, n + 1)
        if w is None:
            return None
        r = _rets(w)
        if r is None:
            return None
        h = fit_hmm(r)
        if h is None:
            return None
        # regime_spread: how far apart the two states' means are. A wide spread
        # means the regime split is real; a narrow one means the fit found two
        # states that are barely different, and bull_prob is not worth much.
        return h.bull_prob if part == "bull_prob" else h.bull_mean - h.bear_mean

    return fn


def _roc(base: FactorFn, lag: int) -> FactorFn:
    """Rate of change of another factor: its value now minus `lag` bars ago."""

    def fn(b: Bars, t: int) -> float | None:
        if t - lag < 0:
            return None
        a, c = base(b, t), base(b, t - lag)
        if a is None or c is None:
            return None
        return a - c

    return fn


for _n in (120, 252):
    _add(f"kalman_distance_{_n}", "model", _n, _kalman(_n, "distance"))
    _add(f"kalman_slope_{_n}", "model", _n, _kalman(_n, "slope"))
    _add(f"kalman_distance_roc5_{_n}", "model", _n + 5, _roc(_kalman(_n, "distance"), 5))
    _add(f"garch_forecast_{_n}", "model", _n + 1, _garch(_n, "forecast"), cost="slow")
    _add(f"garch_rv_ratio_{_n}", "model", _n + 1, _garch(_n, "ratio"), cost="slow")
    _add(f"hmm_bull_prob_{_n}", "model", _n + 1, _hmm(_n, "bull_prob"), cost="slow")
    _add(f"hmm_regime_spread_{_n}", "model", _n + 1, _hmm(_n, "spread"), cost="slow")
_add("hmm_bull_prob_roc5_252", "model", 258, _roc(_hmm(252, "bull_prob"), 5), cost="slow")


# ---------------------------------------------------------------------------
# Panel construction
# ---------------------------------------------------------------------------


def factor_names(
    families: Sequence[str] | None = None,
    include_slow: bool = False,
) -> list[str]:
    """Registry names, optionally filtered by family and cost tier."""
    return [
        name
        for name, spec in FACTOR_REGISTRY.items()
        if (families is None or spec.family in families) and (include_slow or spec.cost == "fast")
    ]


def compute_panel(
    series: PriceSeries,
    names: Sequence[str] | None = None,
    include_slow: bool = False,
) -> dict[str, list[float | None]]:
    """Compute every requested factor at every bar.

    Returns `dict[factor_name, list[value_or_None]]`, each list exactly as long
    as `series.candles` — the shape `rank_factors` expects.

    Bars before a factor's `min_bars` are None rather than a partial-window
    approximation. That is what makes the `coverage` column in the ranking
    output mean something.
    """
    bars = Bars.from_candles(series.candles)
    n = len(bars)
    selected = list(names) if names is not None else factor_names(include_slow=include_slow)

    panel: dict[str, list[float | None]] = {}
    for name in selected:
        spec = FACTOR_REGISTRY[name]
        col: list[float | None] = [None] * n
        for t in range(spec.min_bars - 1, n):
            try:
                col[t] = spec.fn(bars, t)
            except (ValueError, ZeroDivisionError, OverflowError):
                # A numeric edge case is missing data, not a crashed panel. The
                # factor is None at this bar and coverage records the loss.
                col[t] = None
        panel[name] = col
    return panel


def factor_families() -> dict[str, list[str]]:
    """Factor names grouped by family, for legible reporting."""
    out: dict[str, list[str]] = {}
    for name, spec in FACTOR_REGISTRY.items():
        out.setdefault(spec.family, []).append(name)
    return out


# ---------------------------------------------------------------------------
# Reporting helpers: low-signal flagging and correlation clustering
# ---------------------------------------------------------------------------

LOW_SIGNAL_IC = 0.02


def flag_low_signal(scores: Sequence[object]) -> dict[str, bool]:
    """Mark each family whose factors are all below `LOW_SIGNAL_IC`.

    Roadmap rule: a family that measures as noise stays in the library for
    completeness but is labelled, rather than quietly presented as useful.
    Takes `FactorScore`-like objects (duck-typed on `.name` and `.rank_ic`) so
    this module does not depend on the ranking module.
    """
    best: dict[str, float] = {}
    for s in scores:
        name = getattr(s, "name", None)
        ic = getattr(s, "rank_ic", None)
        spec = FACTOR_REGISTRY.get(name) if isinstance(name, str) else None
        if spec is None or ic is None:
            continue
        best[spec.family] = max(best.get(spec.family, 0.0), abs(float(ic)))
    return {fam: v < LOW_SIGNAL_IC for fam, v in best.items()}


def factor_clusters(
    panel: dict[str, list[float | None]],
    threshold: float = 0.9,
    max_factors: int = 200,
) -> list[list[str]]:
    """Group factors whose values move together, so the ranking output can be
    read as "N independent ideas" rather than "500 rows".

    Greedy single-pass clustering: walk factors in registry order, put each one
    into the first cluster whose representative it correlates with at or above
    `threshold`, else start a new cluster. Greedy is not the optimal clustering,
    but it is deterministic, O(factors x clusters), and answers the only
    question being asked — has this family saturated?

    `max_factors` bounds the cost; correlating 500 columns pairwise is the one
    genuinely quadratic thing here.
    """
    clusters: list[list[str]] = []
    reps: list[list[float | None]] = []

    for name in list(panel)[:max_factors]:
        col = panel[name]
        placed = False
        for i, rep in enumerate(reps):
            pairs = [(a, c) for a, c in zip(col, rep) if a is not None and c is not None]
            if len(pairs) < 10:
                continue
            c = _corr([a for a, _ in pairs], [b for _, b in pairs])
            if c is not None and abs(c) >= threshold:
                clusters[i].append(name)
                placed = True
                break
        if not placed:
            clusters.append([name])
            reps.append(col)

    return clusters
